mapper.select:
SELECT id, name, state, payment_type, partner_id, amount, currency_id, date, journal_id, memo, invoice_ref, origin_ref, journal_entry_ref, company_id FROM account_payment
AND ( name ILIKE CONCAT('%', #{query.keyword}, '%') OR memo ILIKE CONCAT('%', #{query.keyword}, '%') OR invoice_ref ILIKE CONCAT('%', #{query.keyword}, '%') OR origin_ref ILIKE CONCAT('%', #{query.keyword}, '%') OR journal_entry_ref ILIKE CONCAT('%', #{query.keyword}, '%') )
AND payment_type = #{query.paymentType}
AND state = #{query.state}
AND invoice_ref = #{query.invoiceRef}
AND origin_ref = #{query.originRef}
AND journal_entry_ref = #{query.journalEntryRef}
ORDER BY id DESC
